package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetIgnoreSurroundingSpaces_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_WithIgnoreSurroundingSpacesTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(true);
        assertTrue(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_WithIgnoreSurroundingSpacesFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreSurroundingSpaces(false);
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_TDF() {
        CSVFormat format = CSVFormat.TDF;
        assertTrue(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_Excel() {
        CSVFormat format = CSVFormat.EXCEL;
        // EXCEL is DEFAULT.withIgnoreEmptyLines(false).withAllowMissingColumnNames()
        // which doesn't set ignoreSurroundingSpaces to true, so it's false by default
        assertFalse(format.getIgnoreSurroundingSpaces());
    }

    @Test
    void testGetIgnoreSurroundingSpaces_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        assertFalse(format.getIgnoreSurroundingSpaces());
    }
}
